// ============================================================
// Asset Catalog Query API ,  Filter and Build JSON Response
// ============================================================

// --- GRAB WEBHOOK BODY ---
// If your Webhook node is renamed, update the string below to match.
const webhookData = $('1. API Request').first().json;
const body = webhookData.body || {};
const filters = body.filters || {};

// --- GRAB ALL ROWS FROM DATA TABLE ---
const allRows = $input.all().map(item => item.json);

// --- FILTER HELPERS ---
const contains = (rowValue, searchText) => {
    if (!searchText || !searchText.toString().trim()) return true;
    if (rowValue === null || rowValue === undefined) return false;
    return rowValue.toString().toLowerCase().includes(searchText.toString().toLowerCase().trim());
};

const equals = (rowValue, searchText) => {
    if (!searchText || !searchText.toString().trim()) return true;
    if (rowValue === null || rowValue === undefined) return false;
    return rowValue.toString().toLowerCase() === searchText.toString().toLowerCase().trim();
};

// --- APPLY FILTERS ---
// Semantics must match Query Form exactly for consistency
const filtered = allRows.filter(row =>
    contains(row.asset_id, filters.asset_id) &&
    contains(row.asset_name, filters.asset_name) &&
    contains(row.owning_team, filters.admin_group) &&
    contains(row.asset_type, filters.asset_type) &&
    equals(row.status, filters.status) &&
    contains(row.service_groue, filters.service_groue) &&
    contains(row.customer, filters.customer) &&
    contains(row.business_unit, filters.business_unit) &&
    equals(row.monitoring_enabled, filters.monitoring_enabled) &&
    equals(row.scanning_enabled, filters.scanning_enabled) &&
    equals(row.is_critical, filters.is_critical) &&
    equals(row.is_external, filters.is_external)
);

// --- APPLY LIMIT ---
const requestedLimit = parseInt(body.limit);
const limit = Math.min(
    isNaN(requestedLimit) || requestedLimit <= 0 ? 1000 : requestedLimit,
    5000
);
const results = filtered.slice(0, limit);

// --- STRIP TO PUBLIC CONTRACT FIELDS ---
// Consumers only depend on these. Internal fields (id, createdAt, updatedAt)
// intentionally excluded from the response contract.
const publicFields = [
    'asset_id', 'asset_name', 'display_name', 'asset_type', 'status',
    'service_category', 'service_groue', 'owning_team',
    'service_tier', 'customer', 'business_unit',
    'risk_tier', 'risk_status', 'monitoring_enabled', 'scanning_enabled',
    'is_critical', 'is_external'
];

const cleanResults = results.map(r => {
    const out = {};
    publicFields.forEach(f => { out[f] = r[f] ?? null; });
    return out;
});

// --- BUILD RESPONSE ---
const response = {
    success: true,
    query: {
        filters_applied: filters,
        limit: limit
    },
    result: {
        total_matched: filtered.length,
        returned: results.length,
        truncated: filtered.length > limit,
        data: cleanResults
    },
    meta: {
        data_source: 'asset_catalog',
        refreshed_by: 'Asset Catalog Datalake Sync',
        freshness_note: 'Refreshed weekday mornings from AWS datalake',
        generated_at: new Date().toISOString()
    }
};

return [{ json: response }];

const errorData = $input.first().json;

const response = {
    success: false,
    error: {
        message: 'An error occurred processing your query',
        details: errorData.execution?.error?.message || 'Unknown internal error',
        timestamp: new Date().toISOString()
    }
};

return [{ json: response }];
